var e=[{id:`L2_1`,type:`narration`,speaker:null,text:{KOREA:`대령님.`,JPN:`大佐。`,ENG:`Colonel.`,TWN:`上校。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`GUARD_EXILER_NPC_NULL`,text:{KOREA:`으악!!`,JPN:`うわあ！！`,ENG:`Aaargh!`,TWN:`啊啊！！`},stage:{bg:`WORKSHOP`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`GUARD_EXILER_NPC_NULL`,text:{KOREA:`쏴라! 마지막 순간까지 포기하지 마라!`,JPN:`撃て！　最後の瞬間まで諦めるな！`,ENG:`Pull the trigger! Don't give up until the very last second!`,TWN:`開火！直到最後一刻也不要放棄！`},stage:{bg:`WORKSHOP`,slots:{L:{char_id:`GUARD_EXILER_NPC_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L10_1`,type:`narration`,speaker:null,text:{KOREA:`저, 대령님 말대로 최선을 다했어요.`,JPN:`私、大佐の言葉を守って全力を尽くしてきました。`,ENG:`Colonel, I did what you asked. I tried my best.`,TWN:`我按照上校說的，用盡全力去做了。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L11_1`,type:`narration`,speaker:null,text:{KOREA:`마지막에, 마지막까지 포기하지 않고 여기까지 왔어요.`,JPN:`最後の最後まで諦めずにここまで来ました。`,ENG:`I didn't give up until the very last second, and I made it all the way here.`,TWN:`直至最後也沒有放棄。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_AP_NULL`,text:{KOREA:`카린 양! 지금이 기회에요!`,JPN:`カリンさん！　今がチャンスです！`,ENG:`Karin! Now's your chance!`,TWN:`卡琳！趁現在！`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_AP_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`으아아아아아아아아아아아아앗!!`,JPN:`うわあああああああああっ！！`,ENG:`Aaaaaaaaaaargh!!`,TWN:`呵啊啊啊啊啊啊啊！！`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L19_1`,type:`narration`,speaker:null,text:{KOREA:`그러니까, 최소한 제 마지막은……`,JPN:`だから、せめて私の最後は……`,ENG:`So, at least for my last moment...`,TWN:`所以，至少在最後一刻……`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`……크헉!!`,JPN:`……くはっ！！`,ENG:`...Kuh!!`,TWN:`……呃！！`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_AP_NULL`,text:{KOREA:`카린 양! 괜찮아요!?`,JPN:`カリンさん！　大丈夫ですか！？`,ENG:`Karin! Are you okay?!`,TWN:`卡琳！你沒事吧？！`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_AP_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`KING_EXILER_NULL_NULL`,text:{KOREA:`<color=#ff3636>그렇군.</color>`,JPN:`<color=#ff3636>そうか。</color>`,ENG:`<color=#ff3636>I see.</color>`,TWN:`<color=#ff3636>看來。</color>`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`KING_EXILER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`KING_EXILER_NULL_NULL`,text:{KOREA:`<color=#ff3636>여기서 너희 둘을 죽여 놓지 않으면.</color>`,JPN:`<color=#ff3636>ここでお前らを殺しておかなければ。</color>`,ENG:`<color=#ff3636>If I don't eliminate you two right now...</color>`,TWN:`<color=#ff3636>如果不在這裡殺了你們二個。</color>`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`KING_EXILER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`KING_EXILER_NULL_NULL`,text:{KOREA:`<color=#ff3636>너희 인간은 계속해서 이 몸의 업을 가로막겠지.</color>`,JPN:`<color=#ff3636>お前ら人間は、いつまでも俺の仕事の邪魔してくるだろうな。</color>`,ENG:`<color=#ff3636>You humans will keep trying to stop me.</color>`,TWN:`<color=#ff3636>你們就會一直妨礙我。</color>`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`KING_EXILER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_AP_NULL`,text:{KOREA:`시끄러워, 침식체.`,JPN:`うるさい、侵食体。`,ENG:`Shut up, C.O.`,TWN:`你閉嘴，侵蝕體。`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_AP_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_AP_NULL`,text:{KOREA:`중얼거리지 말고 어서, 덤벼.`,JPN:`ぶつぶつ言ってないで、早くかかって来な。`,ENG:`Stop muttering to yourself and bring it!`,TWN:`別廢話了，快點來吧！`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_AP_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};